    "glossary.json": {
  "terms": [
    {
      "term": "Advanced Expression（アドバンストエクスプレッション）",
      "definition": "選択肢、演算子、および関数を含むエクスプレッションです。パーツおよびパーツ使用リンクに割り当てて、コンポーネントが製品構造に含まれる条件を指定できます。"
    },
    {
      "term": "Basic Expression（ベーシックエクスプレッション）",
      "definition": "パーツおよびパーツ使用リンクに割り当てることができるオプション選択肢で、コンポーネントが製品構造に含まれる条件を指定します。"
    },
    {
      "term": "Configurable Module（コンフィギュラブルモジュール）",
      "definition": "コンポーネントまたは機能ユニットの設計およびコンフィグレーションにおけるバリエーションを表す1つ以上の子パーツを持つことができるWindchillパーツです。"
    },
    {
      "term": "Configurable Product（コンフィギュラブル製品）",
      "definition": "製品バリエーションの集合を表すトップレベルのエンドアイテムです。例としては、一部の標準コンポーネントを共有する異なるモデルを持つ製品ファミリーがあります。"
    },
    {
      "term": "Configurable Product Structure（コンフィギュラブル製品構造）",
      "definition": "同じ製品構造から複数の製品バリアントを作成する機能をサポートするために、コンフィギュラブルモジュールを含みます。"
    },
    {
      "term": "Conditional Rule（条件付きルール）",
      "definition": "IF/THENステートメントを使用して、オプションフィルタ内の他の選択肢の選択に基づいて、特定のオプション選択肢をインクルード、オン、またはオフにするタイミングを指定するルールです。"
    },
    {
      "term": "Enable Rule（イネーブルルール）",
      "definition": "特定のターゲット選択肢が選択された後に、特定の選択肢のみが選択可能として表示されるようにするルールです。"
    },
    {
      "term": "Exclude Rule（エクスクルードルール）",
      "definition": "互換性のない選択肢の選択を制限するルールです。例えば、110ボルトを選択すると50Hz周波数の選択が防止されます。"
    },
    {
      "term": "Expression Alias（エクスプレッションエイリアス）",
      "definition": "条件付きルール、アドバンストエクスプレッション、および他のエイリアスの作成時に再利用できる名前付きの論理ステートメントです。グローバルな製品管理のための一般的な定義を記録します。"
    },
    {
      "term": "Include Rule（インクルードルール）",
      "definition": "1つのオプション選択肢の選択を1つ以上の関連するオプション選択肢に関連付けるルールです。ソース選択肢を選択すると、ターゲット選択肢が自動的に選択されます。"
    },
    {
      "term": "Module Variant（モジュールバリアント）",
      "definition": "バリアント生成時の選択基準と選択肢の割り当てに基づいて、コンフィギュラブルモジュールのオプションパーツおよびコンポーネントから選択された特定のパーツです。"
    },
    {
      "term": "Option（オプション）",
      "definition": "特定の製品フィーチャーです。オプションには1つ以上の選択肢があり、必須または単一選択に設定でき、特定の製品バリエーションに適用されます。"
    },
    {
      "term": "Option Filter（オプションフィルタ）",
      "definition": "パーツに割り当てられた選択肢と構造内でのパーツの使用に基づいて、製品構造をフィルタリングするために使用される一連の基準です。"
    },
    {
      "term": "Option Manager（オプションマネージャ）",
      "definition": "オプションと選択肢を作成し、オプションセットおよびその他の関連情報を管理する権限を持つWindchillコンテキストロールです。"
    },
    {
      "term": "Option Pool（オプションプール）",
      "definition": "製品で利用可能なすべてのオプションとその選択肢を保持するコンテナです。オプションと選択肢はオプションプール内で管理されます。"
    },
    {
      "term": "Option Set（オプションセット）",
      "definition": "1つ以上のオプションプールからのオプションと選択肢のサブセットで、製品ファミリー内のバリエーションを定義するために使用されます。オプションセットは変更管理対象オブジェクトです。"
    },
    {
      "term": "Parameter（パラメータ）",
      "definition": "パーツコンフィグレーションプロセス中の高度な選択ロジックをサポートするために、コンフィギュラブルモジュールのコンテキスト内でローカルに定義される属性です。"
    },
    {
      "term": "Product Family（製品ファミリー）",
      "definition": "さまざまな機能を提供し、同じパーツのかなりの割合を共有する関連製品のセットです。"
    },
    {
      "term": "Variant（バリアント）",
      "definition": "コンフィグレーションプロセス中に作成される、コンフィギュラブル製品構造の特定のコンフィグレーションを表すパーツまたはパーツ構造です。"
    },
    {
      "term": "Variant Specification（バリアント仕様）",
      "definition": "コンフィグレーションプロセス中に提供されたオプション選択肢とパラメータ値のユーザー入力の記録で、バリアントパーツ構造を生成するために使用されます。"
    },
    {
      "term": "Configurable Module Support（コンフィギュラブルモジュールサポート）",
      "definition": "オプションの製品構造を作成する機能を制御するWindchillプリファレンスです。オプションとバリアントの機能を使用するには「はい」に設定する必要があります。"
    }
  ]
},
